import axios from 'axios';

const API_BASE_URL = 'http://localhost:5000/api'; // Change if your backend is hosted elsewhere

const api = {
  login: async (credentials) => {
    const response = await axios.post(`${API_BASE_URL}/auth/login`, credentials);
    return response.data;
  },

  register: async (userData) => {
    const response = await axios.post(`${API_BASE_URL}/auth/register`, userData);
    return response.data;
  },

  createComplaint: async (complaintData, token) => {
    const response = await axios.post(`${API_BASE_URL}/complaints`, complaintData, {
      headers: { Authorization: `Bearer ${token}` },
    });
    return response.data;
  },

  getComplaints: async (token) => {
    const response = await axios.get(`${API_BASE_URL}/complaints`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    return response.data;
  },

  getComplaintById: async (id, token) => {
    const response = await axios.get(`${API_BASE_URL}/complaints/${id}`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    return response.data;
  },
};

export default api;
